  ('aboriginal-6e11b43e-moex-00157', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-112-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '各級各類學校實施原住民族教育，就原住民族教育法規定之原則與相關條文，下列何者錯誤？', '["鼓勵教師以原住民族語言進行原住民族語文課程教學", "運用行政活動及校園空間，推動原住民族及多元文化教育", "高級中等以下學校於原住民學生就讀時，應對其實施民族教育", "高級中等以下學校課程發展委員會之設置，應聘請當地原住民族或部落具原住民身分之代表參與"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:11+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "506", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
